export default (n) => {
  const seen = new Map();
  for (const child of n.view.item ?? []) {
    const name = child.name ?? "(unnamed)";
    if (!seen.has(name)) seen.set(name, child);
  }
  const needed = [...seen.values()].filter((c) => (c.need ?? 0) > (c.got ?? 0));
  const done = [...seen.values()].filter((c) => (c.got ?? 0) >= (c.need ?? 0) && c.need !== undefined);
  const li = (c) => `<li>${c.name}${c.note ? ` <em>(${c.note})</em>` : ""}</li>`;
  return `<!doctype html><html><head><meta charset="utf-8"><title>Larder</title>
<style>body{font-family:system-ui;max-width:28rem;margin:2rem auto;padding:0 1rem}
h1{font-size:1.4rem}h2{font-size:1rem;color:#666;margin-top:1.5rem}
ul{list-style:none;padding:0}li{padding:.4rem .6rem;border-bottom:1px solid #eee}
.done li{color:#999;text-decoration:line-through}</style></head><body>
<h1>Larder</h1>
<h2>Needed (${needed.length})</h2><ul>${needed.map(li).join("")}</ul>
<h2>In the basket</h2><ul class="done">${done.map(li).join("")}</ul>
</body></html>`;
};
